#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    pid_t pid;

    if (pipe(pipefd) == -1) {
        std::cerr << "Échec de la création du pipe" << std::endl;
        return 1;
    }

    pid = fork();

    if (pid < 0) {
        std::cerr << "Échec du fork" << std::endl;
        return 1;
    } else if (pid > 0) { // Parent
        close(pipefd[0]); // On ferme le bout lecteur du pipe
        std::cout << "Je suis le parent, j'envoie un message..." << std::endl;
        write(pipefd[1], "Bonjour, petit processus!", 25);
        close(pipefd[1]);
        wait(NULL);
    } else { // Child
        close(pipefd[1]); // On ferme le bout ecriture du pipe
        dup2(pipefd[0], STDIN_FILENO); // On remplace l'entrée standard par le pipe
        close(pipefd[0]); // On ferme le bout lecteur
        execlp("bash", "bash", "-c", "cat", (char*)0); // On exécute un shell avec l'entrée standard connectée au pipe
    }

    return 0;
}
```

C'est un petit jeu de rôle avec un pipe et un shell. Le parent envoie un message, le child le reçoit et lit avec `cat`. Enjoy! 👏😉
